import{_ as t,o as e,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const o="/assets/tasks.BBSTdzET.png",p=JSON.parse('{"title":"⚔️ Minecraft 遊戲內每日任務系統","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Task-System.md","filePath":"Mc-Task-System.md"}'),i={name:"Mc-Task-System.md"};function n(l,a,c,d,h,_){return e(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="⚔️-minecraft-遊戲內每日任務系統" tabindex="-1">⚔️ Minecraft 遊戲內每日任務系統 <a class="header-anchor" href="#⚔️-minecraft-遊戲內每日任務系統" aria-label="Permalink to &quot;⚔️ Minecraft 遊戲內每日任務系統&quot;">​</a></h1><p>遊戲內提供了極具挑戰性的每日任務，完成任務是獲取金幣與資源的重要管道。</p><p><img src="'+o+'" alt="遊戲內任務系統"></p><hr><h2 id="📅-1-任務類型與更新" tabindex="-1">📅 1. 任務類型與更新 <a class="header-anchor" href="#📅-1-任務類型與更新" aria-label="Permalink to &quot;📅 1. 任務類型與更新&quot;">​</a></h2><p>每日任務在每天凌晨 0:00 自動更新，每人每日隨機分配：</p><ul><li><strong>擊殺任務</strong>：指定擊殺一定數量的怪物（如 15 隻殭屍）。</li><li><strong>挖掘任務</strong>：指定挖掘一定數量的礦石或方塊（如 20 個煤礦石）。</li></ul><hr><h2 id="📈-2-查詢任務進度" tabindex="-1">📈 2. 查詢任務進度 <a class="header-anchor" href="#📈-2-查詢任務進度" aria-label="Permalink to &quot;📈 2. 查詢任務進度&quot;">​</a></h2><p>在遊戲內，您可以輸入以下指令查看今日任務：</p><ul><li><strong><code>/task</code></strong>：開啟任務面板，顯示當前任務內容、進度百分比以及對應的金幣獎勵。</li></ul><hr><h2 id="🎁-3-領取獎勵" tabindex="-1">🎁 3. 領取獎勵 <a class="header-anchor" href="#🎁-3-領取獎勵" aria-label="Permalink to &quot;🎁 3. 領取獎勵&quot;">​</a></h2><ul><li>當任務進度達到 100% 時，在遊戲內可直接點選任務選單領取獎勵。</li><li><strong>網頁端領取</strong>：您也可以在網頁儀表板首頁的任務卡片中，點選「領取任務獎勵」按鈕，獎勵金幣將直接匯入您的個人帳戶。</li></ul>',14)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
